#include <omp.h>
#include "common.h"

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

extern int omp_num_threads;

static void lud_base_fallback(float *a, int size)
{
    int i, j, k;

    for (i = 0; i < size; i++) {
#pragma omp parallel for private(k) schedule(static)
        for (j = i; j < size; j++) {
            float sum = a[i * size + j];
            for (k = 0; k < i; k++)
                sum -= a[i * size + k] * a[k * size + j];
            a[i * size + j] = sum;
        }

#pragma omp parallel for private(k) schedule(static)
        for (j = i + 1; j < size; j++) {
            float sum = a[j * size + i];
            for (k = 0; k < i; k++)
                sum -= a[j * size + k] * a[k * size + i];
            a[j * size + i] = sum / a[i * size + i];
        }
    }
}

static void lud_diagonal_omp(float *m, int matrix_dim, int offset)
{
    float shadow[BLOCK_SIZE * BLOCK_SIZE];
    int i, j, tx;
    int array_offset = offset * matrix_dim + offset;

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++)
            shadow[i * BLOCK_SIZE + tx] = m[array_offset + tx];
        array_offset += matrix_dim;
    }

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i; j++)
                shadow[tx * BLOCK_SIZE + i] -=
                    shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
            shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
        }

        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i + 1; j++)
                shadow[(i + 1) * BLOCK_SIZE + tx] -=
                    shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
        }
    }

    array_offset = (offset + 1) * matrix_dim + offset;
    for (i = 1; i < BLOCK_SIZE; i++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++)
            m[array_offset + tx] = shadow[i * BLOCK_SIZE + tx];
        array_offset += matrix_dim;
    }
}

static void lud_perimeter_omp(float *m, int matrix_dim, int offset)
{
    int bx;
    int blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;

    if (blocks <= 0)
        return;

#pragma omp parallel for private(bx) schedule(static)
    for (bx = 0; bx < blocks; bx++) {
        float dia[BLOCK_SIZE * BLOCK_SIZE];
        float peri_row[BLOCK_SIZE * BLOCK_SIZE];
        float peri_col[BLOCK_SIZE * BLOCK_SIZE];
        int i, j, idx, array_offset;

        array_offset = offset * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (idx = 0; idx < BLOCK_SIZE; idx++)
                dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
            array_offset += matrix_dim;
        }

        array_offset = offset * matrix_dim + offset + (bx + 1) * BLOCK_SIZE;
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (idx = 0; idx < BLOCK_SIZE; idx++)
                peri_row[i * BLOCK_SIZE + idx] = m[array_offset + idx];
            array_offset += matrix_dim;
        }

        array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (idx = 0; idx < BLOCK_SIZE; idx++)
                peri_col[i * BLOCK_SIZE + idx] = m[array_offset + idx];
            array_offset += matrix_dim;
        }

        for (i = 1; i < BLOCK_SIZE; i++) {
            for (idx = 0; idx < BLOCK_SIZE; idx++) {
                for (j = 0; j < i; j++)
                    peri_row[i * BLOCK_SIZE + idx] -=
                        dia[i * BLOCK_SIZE + j] * peri_row[j * BLOCK_SIZE + idx];
            }
        }

        for (idx = 0; idx < BLOCK_SIZE; idx++) {
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < i; j++)
                    peri_col[idx * BLOCK_SIZE + i] -=
                        peri_col[idx * BLOCK_SIZE + j] * dia[j * BLOCK_SIZE + i];
                peri_col[idx * BLOCK_SIZE + i] /= dia[i * BLOCK_SIZE + i];
            }
        }

        array_offset = (offset + 1) * matrix_dim + offset + (bx + 1) * BLOCK_SIZE;
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (idx = 0; idx < BLOCK_SIZE; idx++)
                m[array_offset + idx] = peri_row[i * BLOCK_SIZE + idx];
            array_offset += matrix_dim;
        }

        array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (idx = 0; idx < BLOCK_SIZE; idx++)
                m[array_offset + idx] = peri_col[i * BLOCK_SIZE + idx];
            array_offset += matrix_dim;
        }
    }
}

static void lud_internal_omp(float *m, int matrix_dim, int offset)
{
    int bx, by;
    int blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;

    if (blocks <= 0)
        return;

#pragma omp parallel for collapse(2) private(by, bx) schedule(static)
    for (by = 0; by < blocks; by++) {
        for (bx = 0; bx < blocks; bx++) {
            int ty, tx, i;
            int global_row_id = offset + (by + 1) * BLOCK_SIZE;
            int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

            for (ty = 0; ty < BLOCK_SIZE; ty++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    float sum = 0.0f;
                    for (i = 0; i < BLOCK_SIZE; i++)
                        sum += m[(global_row_id + ty) * matrix_dim + offset + i] *
                               m[(offset + i) * matrix_dim + global_col_id + tx];
                    m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
                }
            }
        }
    }
}

void lud_omp(float *m, int matrix_dim)
{
    int offset = 0;

    if (omp_num_threads > 0)
        omp_set_num_threads(omp_num_threads);

    if (matrix_dim <= 0)
        return;

    if (matrix_dim < BLOCK_SIZE || (matrix_dim % BLOCK_SIZE) != 0) {
        lud_base_fallback(m, matrix_dim);
        return;
    }

    for (offset = 0; offset < matrix_dim - BLOCK_SIZE; offset += BLOCK_SIZE) {
        lud_diagonal_omp(m, matrix_dim, offset);
        lud_perimeter_omp(m, matrix_dim, offset);
        lud_internal_omp(m, matrix_dim, offset);
    }

    lud_diagonal_omp(m, matrix_dim, offset);
}
